using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 = 4 pages")]
    [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
    [DataRow(0, 5, 0, DisplayName = "0 items, page size 5 = 0 pages")]
    [DataRow(1, 5, 1, DisplayName = "1 item, page size 5 = 1 page")]
    [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages")]
    [DataRow(15, 5, 3, DisplayName = "15 items, page size 5 = 3 pages")]
    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Arrange
        var items = new List<int>();

        // Act
        var list = new PaginatedList<int>(items, count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_PageOne_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        // Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_PageTwo_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        // Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange - 10 items, 5 per page = 2 pages. On page 2 (last).
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        // Assert
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        // Arrange - 10 items, 5 per page = 2 pages. On page 1.
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        // Assert
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectFirstPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 3);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(2, result[1]);
        Assert.AreEqual(3, result[2]);
    }

    [TestMethod]
    public void Create_ReturnsCorrectMiddlePage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 3);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(4, result[0]);
        Assert.AreEqual(5, result[1]);
        Assert.AreEqual(6, result[2]);
    }

    [TestMethod]
    public void Create_ReturnsCorrectLastPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 4, 3);

        // Assert
        Assert.AreEqual(4, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(10, result[0]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = new List<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(0, result.Count);
    }
}

