using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new HomeController(context);

        // Act
        var result = controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void About_ReturnsViewResultWithGroupedData()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        var date1 = new DateTime(2023, 9, 1);
        var date2 = new DateTime(2024, 1, 15);
        context.Students.AddRange(
            new Student { LastName = "A", FirstMidName = "X", EnrollmentDate = date1 },
            new Student { LastName = "B", FirstMidName = "Y", EnrollmentDate = date1 },
            new Student { LastName = "C", FirstMidName = "Z", EnrollmentDate = date2 }
        );
        context.SaveChanges();

        var controller = new HomeController(context);

        // Act
        var result = controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        // Check the groups contain the right student counts
        var group1 = model.FirstOrDefault(g => g.EnrollmentDate == date1);
        var group2 = model.FirstOrDefault(g => g.EnrollmentDate == date2);
        Assert.IsNotNull(group1);
        Assert.IsNotNull(group2);
        Assert.AreEqual(2, group1.StudentCount);
        Assert.AreEqual(1, group2.StudentCount);
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new HomeController(context);

        // Act
        var result = controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new HomeController(context);

        // Act
        var result = controller.Contact() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new HomeController(context);

        // Act
        var result = controller.Error();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessageAndReturnsView()
    {
        // Arrange
        using var context = CreateContext();
        var controller = new HomeController(context);

        // Act
        var result = controller.Unauthorized() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", controller.ViewBag.Message);
    }
}

