using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private CoursesController CreateController(SchoolContext context)
    {
        var mockEnv = new Mock<IWebHostEnvironment>();
        mockEnv.Setup(e => e.WebRootPath).Returns("/fake/webroot");
        mockEnv.Setup(e => e.ContentRootPath).Returns("/fake/content");
        var mockLogger = new Mock<ILogger<CoursesController>>();

        var controller = new CoursesController(context, mockEnv.Object, mockLogger.Object);
        var httpContext = new DefaultHttpContext();
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = httpContext
        };
        return controller;
    }

    private void SeedDepartment(SchoolContext context, int deptId = 1)
    {
        if (!context.Departments.Any(d => d.DepartmentID == deptId))
        {
            context.Departments.Add(new Department
            {
                DepartmentID = deptId,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1)
            });
            context.SaveChanges();
        }
    }

    [TestInitialize]
    public void TestInitialize()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    // ---- Index Tests ----

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        // Arrange
        using var context = CreateContext();
        SeedDepartment(context);
        context.Courses.Add(new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 });
        context.Courses.Add(new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 1 });
        context.SaveChanges();
        var controller = CreateController(context);

        // Act
        var result = controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_NoCourses_ReturnsEmptyList()
    {
        // Arrange
        using var context = CreateContext();
        var controller = CreateController(context);

        // Act
        var result = controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
