using System;
using System.Collections.Generic;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private NotificationsController CreateController(SchoolContext context)
    {
        var controller = new NotificationsController(context);
        var httpContext = new DefaultHttpContext();
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = httpContext
        };
        return controller;
    }

    private T GetProperty<T>(object obj, string propertyName)
    {
        var prop = obj.GetType().GetProperty(propertyName);
        Assert.IsNotNull(prop, $"Property '{propertyName}' not found on {obj.GetType().Name}");
        return (T)prop.GetValue(obj);
    }

    [TestInitialize]
    public void TestInitialize()
    {
        // Drain the static notification queue to prevent cross-test contamination
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    // ---- GetNotifications Tests ----

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Arrange
        using var context = CreateContext();
        var controller = CreateController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        Assert.IsTrue(GetProperty<bool>(value, "success"));
        Assert.AreEqual(0, GetProperty<int>(value, "count"));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange
        using var context = CreateContext();
        var controller = CreateController(context);

        // Pre-populate the static queue via the service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsTrue(GetProperty<bool>(value, "success"));
        Assert.AreEqual(2, GetProperty<int>(value, "count"));

        var notifications = GetProperty<List<Notification>>(value, "notifications");
        Assert.AreEqual(2, notifications.Count);
        Assert.AreEqual("Student", notifications[0].EntityType);
        Assert.AreEqual("Course", notifications[1].EntityType);
    }

    [TestMethod]
    public void GetNotifications_LimitsToTenNotifications()
    {
        // Arrange
        using var context = CreateContext();
        var controller = CreateController(context);

        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), $"Student{i}", EntityOperation.CREATE);
        }

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.AreEqual(10, GetProperty<int>(value, "count"));
    }

    // ---- MarkAsRead Tests ----

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Arrange
        using var context = CreateContext();
        var controller = CreateController(context);

        // Act
        var result = controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsTrue(GetProperty<bool>(value, "success"));
    }

    // ---- Index Tests ----

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Arrange
        using var context = CreateContext();
        var controller = CreateController(context);

        // Act
        var result = controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }
}

